INSERT INTO mcp_server_tools VALUES(37,8,'dump_codebase_context','Recursively reads text files from a specified directory, respecting .gitignore rules and skipping binary files, then concatenates content with file path headers/footers','{"type":"object","properties":{"base_path":{"type":"string","description":"Absolute path to the project directory to scan"},"num_chunks":{"type":"integer","description":"Total number of chunks to divide the output into (default: 1)","default":1},"chunk_index":{"type":"integer","description":"1-based index of the chunk to return (default: 1)","default":1}},"required":["base_path"]}');
INSERT INTO mcp_server_tools VALUES(38,9,'scan_code','Scans a specified directory for code files and returns a list of definitions according to the provided filters',unistr('{\u000a  "type": "object",\u000a  "properties": {\u000a    "directory": {"type": "string", "description": "Absolute path to the directory to scan."},\u000a    "filePatterns": {"type": "array", "items": {"type": "string"}, "description": "Glob patterns for files.", "default": ["**/*.js", "**/*.jsx", "**/*.ts", "**/*.tsx", "**/*.cs", "**/*.php", "**/*.css", "**/*.py"]},\u000a    "outputFormat": {"type": "string", "enum": ["xml", "markdown", "json"], "default": "markdown"},\u000a    "detailLevel": {"type": "string", "enum": ["minimal", "standard", "detailed"], "default": "standard"},\u000a    "includeTypes": {"type": "array", "items": {"type": "string"}},\u000a    "excludeTypes": {"type": "array", "items": {"type": "string"}},\u000a    "includeModifiers": {"type": "array", "items": {"type": "string"}},\u000a    "excludeModifiers": {"type": "array", "items": {"type": "string"}},\u000a    "namePattern": {"type": "string", "description": "Regex pattern for names."},\u000a    "excludeNamePattern": {"type": "string", "description": "Regex pattern to exclude names."},\u000a    "includePaths": {"type": "array", "items": {"type": "string"}},\u000a    "excludePaths": {"type": "array", "items": {"type": "string"}}\u000a  },\u000a  "required": ["directory"]\u000a}'));
INSERT INTO mcp_server_tools VALUES(39,10,'review_code','Review code with bias mitigation strategies. Supports two modes: bias_aware (default, reduces false positives) and adversarial (thorough review, may have false positives). Requires detected generation model.','{"type":"object","properties":{"code":{"type":"string","description":"The code to review"},"generationModel":{"type":"string","description":"Model that generated the code"},"language":{"type":"string","description":"Programming language"},"context":{"type":"string","description":"Additional context about the code"},"reviewType":{"type":"string","enum":["security","performance","maintainability","general"],"description":"Type of review to perform"},"reviewStrategy":{"type":"string","enum":["bias_aware","adversarial"],"description":"Review strategy: bias_aware (default) or adversarial"}},"required":["code","generationModel"]}');
INSERT INTO mcp_server_tools VALUES(40,10,'detect_model_from_authors','Detect AI model from commit author information. Parses Co-Authored-By trailers to identify Claude, GPT, Copilot, Gemini, and other AI tools.','{"type":"object","properties":{"authors":{"type":"array","description":"Array of author objects from GitHub API","items":{"type":"object"}}},"required":["authors"]}');
