INSERT INTO mcp_server_tools VALUES(88,15,'add_code_to_graph','Performs a one-time scan of a local folder to add its code to the graph. Ideal for indexing libraries, dependencies, or projects not being actively modified. Returns a job ID for background processing.','{"type": "object", "properties": {"path": {"type": "string", "description": "Path to the directory or file to add."}, "is_dependency": {"type": "boolean", "description": "Whether this code is a dependency.", "default": false}}, "required": ["path"]}');
INSERT INTO mcp_server_tools VALUES(89,15,'watch_directory','Performs an initial scan of a directory and then continuously monitors it for changes, automatically keeping the graph up-to-date. Ideal for projects under active development. Returns a job ID for the initial scan.','{"type": "object", "properties": {"path": {"type": "string", "description": "Path to directory to watch"}}, "required": ["path"]}');
INSERT INTO mcp_server_tools VALUES(90,15,'find_code','Find relevant code snippets related to a keyword (e.g., function name, class name, or content).','{"type": "object", "properties": {"query": {"type": "string", "description": "Keyword or phrase to search for"}, "fuzzy_search": {"type": "boolean", "description": "Whether to use fuzzy search", "default": false}, "edit_distance": {"type": "number", "description": "Edit distance for fuzzy search (between 0-2)", "default": 2}}, "required": ["query"]}');
INSERT INTO mcp_server_tools VALUES(91,15,'analyze_code_relationships','Analyze code relationships like who calls this function or class hierarchy. Supported query types: find_callers, find_callees, find_all_callers, find_all_callees, find_importers, who_modifies, class_hierarchy, overrides, dead_code, call_chain, module_deps, variable_scope, find_complexity, find_functions_by_argument, find_functions_by_decorator.','{"type": "object", "properties": {"query_type": {"type": "string", "description": "Type of relationship query to run.", "enum": ["find_callers", "find_callees", "find_all_callers", "find_all_callees", "find_importers", "who_modifies", "class_hierarchy", "overrides", "dead_code", "call_chain", "module_deps", "variable_scope", "find_complexity", "find_functions_by_argument", "find_functions_by_decorator"]}, "target": {"type": "string", "description": "The function, class, or module to analyze."}, "context": {"type": "string", "description": "Optional: specific file path for precise results."}}, "required": ["query_type", "target"]}');
INSERT INTO mcp_server_tools VALUES(92,15,'execute_cypher_query','Fallback tool to run a direct, read-only Cypher query against the code graph. Use this for complex questions not covered by other tools.','{"type": "object", "properties": {"cypher_query": {"type": "string", "description": "The read-only Cypher query to execute."}}, "required": ["cypher_query"]}');
INSERT INTO mcp_server_tools VALUES(93,15,'find_dead_code','Find potentially unused functions (dead code) across the entire indexed codebase, optionally excluding functions with specific decorators.','{"type": "object", "properties": {"exclude_decorated_with": {"type": "array", "items": {"type": "string"}, "description": "Optional: A list of decorator names (e.g., @app.route) to exclude from dead code detection.", "default": []}}}');
INSERT INTO mcp_server_tools VALUES(94,15,'calculate_cyclomatic_complexity','Calculate the cyclomatic complexity of a specific function to measure its complexity.','{"type": "object", "properties": {"function_name": {"type": "string", "description": "The name of the function to analyze."}, "path": {"type": "string", "description": "Optional: The full path to the file containing the function for a more specific query."}}, "required": ["function_name"]}');
INSERT INTO mcp_server_tools VALUES(95,15,'find_most_complex_functions','Find the most complex functions in the codebase based on cyclomatic complexity.','{"type": "object", "properties": {"limit": {"type": "integer", "description": "The maximum number of complex functions to return.", "default": 10}}}');
INSERT INTO mcp_server_tools VALUES(96,15,'add_package_to_graph','Add a package to the graph by discovering its location. Supports multiple languages. Returns immediately with a job ID.','{"type": "object", "properties": {"package_name": {"type": "string", "description": "Name of the package to add (e.g., requests, express, moment, lodash)."}, "language": {"type": "string", "description": "The programming language of the package.", "enum": ["python", "javascript", "typescript", "java", "c", "go", "ruby", "php", "cpp"]}, "is_dependency": {"type": "boolean", "description": "Mark as a dependency.", "default": true}}, "required": ["package_name", "language"]}');
