INSERT INTO mcp_server_tools VALUES(101,15,'visualize_graph_query','Generates a URL to visualize the results of a Cypher query in the Neo4j Browser.','{"type": "object", "properties": {"cypher_query": {"type": "string", "description": "The Cypher query to visualize."}}, "required": ["cypher_query"]}');
