PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE mcp_servers (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  slug TEXT UNIQUE NOT NULL,
  description TEXT,
  homepage TEXT,
  repository TEXT,
  install_method TEXT CHECK(install_method IN ('brew', 'npx', 'pip', 'docker', 'manual')),
  install_command TEXT,
  dockerized INTEGER DEFAULT 0 CHECK(dockerized IN (0,1,2)),
  language TEXT,
  transport TEXT CHECK(transport IN ('stdio', 'sse', 'http-stream')),
  config_schema TEXT,
  locale TEXT DEFAULT 'en',
  pricing TEXT CHECK(pricing IN ('free', 'paid', 'freemium')),
  pricing_notes TEXT,
  features TEXT,
  source_registry TEXT,
  source_url TEXT,
  stars INTEGER,
  last_updated TEXT,
  discovered_at TEXT DEFAULT (datetime('now')),
  refreshed_at TEXT
);
CREATE TABLE mcp_server_tools (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  server_id INTEGER NOT NULL,
  name TEXT NOT NULL,
  description TEXT,
  input_schema TEXT,
  FOREIGN KEY (server_id) REFERENCES mcp_servers(id) ON DELETE CASCADE
);
CREATE TABLE mcp_server_deps (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  server_id INTEGER NOT NULL,
  name TEXT NOT NULL,
  kind TEXT,
  required INTEGER DEFAULT 1,
  version_constraint TEXT,
  notes TEXT,
  FOREIGN KEY (server_id) REFERENCES mcp_servers(id) ON DELETE CASCADE
);
CREATE TABLE mcp_server_assessments (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  server_id INTEGER NOT NULL,
  domain TEXT,
  relevance_score INTEGER CHECK(relevance_score BETWEEN 0 AND 100),
  coverage_pct INTEGER CHECK(coverage_pct BETWEEN 0 AND 100),
  recommendation TEXT CHECK(recommendation IN ('reuse', 'extend', 'create')),
  notes TEXT,
  assessed_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (server_id) REFERENCES mcp_servers(id) ON DELETE CASCADE
);
COMMIT;
